input.command:
kubectl -n elasticsearch patch statefulset es-cluster --type=strategic-merge-patch -p '{
  "spec": {
    "template": {
      "spec": {
        "volumes": [
          {
            "name": "file-realm",
            "secret": {
              "secretName": "es-file-realm-aggregate"
            }
          }
        ],
        "containers": [
          {
            "name": "elasticsearch",
            "volumeMounts": [
              {
                "name": "file-realm",
                "mountPath": "/usr/share/elasticsearch/config/users",
                "subPath": "users"
              },
              {
                "name": "file-realm",
                "mountPath": "/usr/share/elasticsearch/config/users_roles",
                "subPath": "users_roles"
              },
              {
                "name": "file-realm",
                "mountPath": "/usr/share/elasticsearch/config/roles.yml",
                "subPath": "roles.yml"
              }
            ]
          }
        ]
      }
    }
  }
}'

